const info = $('get_info_user')?.first();
const activated = info?.json?.is_bot_activated;

return activated !== null && activated !== undefined
  ? info
  : $('add_row_user_chat')?.first();

const required = $('cfg_get_constants').first().json.values.required_fields || [];
const data = $('deja_nodo_primero').first().json;

const required_fields_values = [];
required.forEach((field) => {
  required_fields_values.push({ [field]: data?.[field] ?? null });
});


return { required_fields_values };

